            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "The Child With the List",
                text = "*(They show you the list, shy but proud, names in a child's painstaking hand.)* It started because of old Maman Bell. *(they explain, serious.)* She lived next to us, and she had *nobody*, and when she *died*, the day after, it was like she'd — like she'd *never been there at all.* Nobody *said* her name. The *room* got rented to someone *new* and they didn't even *know* a Maman Bell had *lived* and *died* in it. *(they frown at the unfairness.)* And I thought — that's *wrong.* That's the *worst* thing I ever heard of. That you can *live* a whole *life* and then be *gone* so *complete* that it's like *subtraction*, like the world just *takes you out* and *closes up the hole.* *(they tap the list.)* So I write them down. The ones nobody else will. Maman Bell was *first.* *(they look up at you.)* The grown-ups think it's *morbid.* A child keeping a list of *dead* nobodies. They want me to play at *something cheerful.* *(fiercely, in the way only a serious child can be.)* But I *asked* one of them — *\"if you died and nobody remembered, wouldn't you want* one *person to have written your name down?\"* — and they *didn't have an answer*, they just looked *sad* and *changed the subject*, which is what grown-ups do when a child is *right.* *(they go back to writing.)* So I keep the list. Somebody has to. Might as well be me. I've got *good* handwriting and I'm *not* scared of dead people. Those are the *main* qualifications, I think.",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 17] \"Do you know, child, that you invented something thousands of years old without being told? There's a girl named Lula, in a city far from here, doing exactly this — and a choir, and an indexer, and a clerk of memory. Nobody taught any of you. The *list* keeps being *reinvented*, in every age, by a serious child who can't bear the subtraction.\"", nextNodeId = "reinvented", checkAbility = Ability.Wisdom, checkDC = 17 },
