                onEnter = new[] { new FlagClause { key = "npc.listkeeper_names", op = FlagOp.SetTrue }, new FlagClause { key = "sq.childs_list", op = FlagOp.SetTrue }, new FlagClause { key = "act5.remembering_regenerates", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "after", speaker = "The Child With the List",
                text = "*(The child's certainty falters, and for a moment they look their actual age — small, and a little frightened by the size of the question.)* When it's full. *(they look at the list, which is, you see, nearly out of room.)* ...I *have* thought about it. *(quietly.)* It scares me. Because *I'm* going to be *full* someday too — not the *parchment*, *me* — I'm going to *grow up*, or *get sick*, or *one day* I'll *die*, and then *who* writes *my* name down? Who keeps the *list* when the *list-keeper* needs *keeping?* *(they pick at the parchment.)* I used to think I had to do it *forever*, *alone*, and that was *too heavy*, it made me want to *stop.* *(then, slowly, they brighten, working it out as they speak.)* But — you said there's a *Lula.* And a *choir.* And *others.* Doing the same thing, *not* knowing about *me.* *(their eyes widen.)* So when *my* list is *full* — when *I'm* full — it doesn't *matter* if *this* parchment is *lost*, because *somewhere* there's *another* serious child *starting theirs.* The *list* isn't *this paper.* The *list* is the *deciding-to-keep-one.* And *that* can't be *full*, and can't be *lost*, because it lives in *whatever child next* can't *stand* the *subtraction.* *(they hug the parchment, relieved.)* I don't have to carry it *forever.* I just have to carry it *while it's mine*, and *trust* the *next* one *starts.* *(they look up, the fear gone.)* Will you — if you *meet* the next one, somewhere far away, a serious child with a *new* list — will you tell them *I* was here? That there was a *me*, before them, with *good handwriting?* That's all I want, really. Not to be *carried.* Just to be *one of the ones who kept it, in my turn.*",
