            NpcAnyListkeeperDialogue = g;
        }

        private void BuildNpcAnyPriorloopDialogue()
        {
            var g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "npc.any.priorloop";
            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "A Traveler With Your Eyes",
                text = "*(At a crossroads between eras — the kind of liminal place the Spellplague left scattered through time — you meet a traveler, and the meeting stops you cold, because while the face is not *quite* yours, the *eyes* are, and the *crack* in their soul that matches the crack in yours hums between you like two struck tuning-forks. They are *worn* in a way you are not yet, harder, more certain, a few long steps further down a road you both walk — but not *gone*, not the warden, not the Last Returned. Something in between. They look at you with recognition and a terrible tenderness.)* ...Oh. *(quietly.)* You're an *earlier* one. *(they almost smile.)* Look at you. So much *road* still ahead of you. So much you don't *know* yet. I'd forgotten we ever looked that... *unhardened.*",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.priorloop_met", op = FlagOp.SetTrue }, new FlagClause { key = "act5.faced_the_loop", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "The Returned Before You",
                text = "*(They sit at the crossroads, and you sit across from them, two versions of one soul at different distances from the same end.)* Let me tell you what I *am*, so you can *use* it. *(quietly.)* I'm a *Returned*, like you. From a *loop* a few turns *ahead* of yours — or *behind*, the loop doesn't *number* cleanly. I walked the road you're walking. Met the *coffin-man*, the *complaint*, the *dog.* Reached the *Court.* Met *Jergal*, and the *Ledger*, and — *(their jaw tightens)* — and the *Last Returned.* The *warden.* The *me* at the *end.* *(they look at their own hands.)* And I *swore* I wouldn't *become* him. I was *certain* — as certain as *you* are *right now* — that *I'd* be the one to *break* it. *(softly.)* And then I reached the *Wall*, and saw the *billions*, and felt the *fear* — *the dark might be worse* — and I — *(they can't quite say it.)* I didn't take the *crown.* Not *all* the way. But I *hesitated.* I chose *\"not yet.\"* I decided to *loop once more* and *figure out something safer* — and *that*, it turns out, is *how* it *starts.* Not with *seizing* the crown. With *postponing* the *leap.* *(they meet your eyes, and the warning is total.)* I am *further* down the road than you, and I am *harder* than you, and I can *feel* myself *becoming* him, *one hesitation at a time* — and I came to this *crossroads* to do the *one* thing I *still* can: *warn the earlier one.* *Warn you.* *(fiercely.)* Don't *hesitate* at the Wall. Don't choose *\"not yet.\"* Don't *loop once more to be safe.* The *leap* never gets *less* terrifying. You only get *harder* and *more* certain that *postponing* is *wisdom.* *Be* the one who *leaps* while still *soft* enough to be *afraid* and do it *anyway.*",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 18] \"You came to warn me — which means the loop isn't a closed circle, it's a *chain*, and the links can *talk.* Each of us leaving a warning for the one behind. That's the annotator in Karsus's margins. That's the Revenant's map. We've been *passing notes down the loop* — and one of these notes is finally going to reach a Returned soft enough to act on it. Let it be me.\"", nextNodeId = "chain", checkAbility = Ability.Wisdom, checkDC = 18, failNodeId = "fade" },
                    new DialogueChoice { text = "\"You said you're becoming him one hesitation at a time. Then you're not gone yet — there's still a *you* in there, soft enough to have walked to this crossroads to warn a stranger. *That* you. Can *that* you still turn back, or are you only able to save *me?*\"", nextNodeId = "turnback" },
                    new DialogueChoice { text = "\"Tell me the exact moment. The hesitation that started it. Not the crown — the small choice before the crown, the 'not yet' that felt like wisdom. If I know the precise shape of the trap, I can feel it closing *before* it does.\"", nextNodeId = "moment", effects = new[] { new FlagClause { key = "act5.knows_the_trap", op = FlagOp.SetTrue } } },
                    new DialogueChoice { text = "\"We're the same soul. So this isn't you warning me — it's *us*, warning *ourselves*, across the loop. Whatever breaks the chain frees *all* of us, every link, you included. So help me leap, and you're not just saving the next one. You're saving the one who *hesitated.* You.\"", nextNodeId = "together", effects = new[] { new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 3 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "chain", speaker = "The Returned Before You",
                text = "*(They go very still, and then a slow, astonished light breaks across the worn face.)* ...A chain. That can *talk.* *(quietly.)* Not a *circle.* A *chain.* *(they look at their own hands as though seeing them new.)* I came here on an *impulse* I didn't *examine* — just a *certainty* that I *had* to *warn* the *earlier* one, that I *couldn't* let *you* walk it *blind* the way *I* did. *(their voice strengthens.)* And you're saying that *impulse* — that *passing the warning down* — is the *same* thing as the *hand in Karsus's margins.* The *Revenant's* map scratched over *forty years.* The *prior* Returned, *each* leaving a *note* for the *next.* *(fiercely.)* We've been *trying to break the loop from inside it for uncounted turns* — *not* by *seizing* anything, but by *each* of us *leaving a warning a little clearer than the last.* *(they grip your arm.)* And the loop *holds* only as long as *every* warning *arrives too late* — to a Returned *already* too *hardened* to *heed* it. *(their eyes blaze.)* But the warnings are getting *better.* The *Revenant* turned his into a *map.* I'm telling *you* the *exact* trap, *out loud*, *soft* enough that you *still* believe in the *leap.* *(softly, hopefully.)* You might be the one, *earlier* one. The link *soft* enough, with a *warning clear* enough, *finally* aligned. *(they meet your eyes.)* Don't let my *note* arrive too late like all the *others.* *Read* it *now*, while you're *young* enough to *act.* *Leap* at the Wall. And when you *do* — the *whole chain*, *every* link of *us* who *hesitated* and *passed the note*, *breaks* free at *once.* I *came* to *warn* you. *Let* it be the *warning* that finally *worked.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.priorloop_chain", op = FlagOp.SetTrue }, new FlagClause { key = "act5.loop_can_break", op = FlagOp.SetTrue }, new FlagClause { key = "act3.returned_annotator", op = FlagOp.SetTrue }, new FlagClause { key = "act3.loop_glimpsed", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "turnback", speaker = "The Returned Before You",
                text = "*(The question lands hard, and the worn face crumples, the hardness cracking to show the frightened soul still trapped inside it.)* Can *that* me still turn back. *(very quietly.)* ...I don't *know.* *(a long silence.)* That's the *honest* answer, and it's the one that *frightens* me most. *(they look at their hands.)* I'm *further* than you. *Harder.* The *crown's* not *on* my head — but its *shadow* is, and every *loop* I *hesitate*, the shadow *deepens*, and I can *feel* the *day* coming when I'll *reach* the Wall and *not* hesitate *toward* the leap but *toward* the *crown*, and *take* it, and *become* the *warden*, and *wait* at the *end* for the *next* of us. *(their voice shakes.)* So *can* I turn back? *Maybe.* I'm *soft* enough, *still*, to have *walked* to this crossroads to *warn* a *stranger* who's *me.* That's — that's *not nothing.* A *fully* hardened *warden* doesn't *warn.* He *recruits.* *(they meet your eyes.)* But I *fear* I'm too far to *leap* *myself* — that I've *hesitated* too many times, that the *fear* has *too* much *practice* in me now. *(quietly, with terrible courage.)* So I've made a *different* peace. Maybe *I* can't *break* the loop. But I can *spend* what *softness* I have *left* making *sure you can.* *(fiercely.)* That's *why* I'm *here.* Not to *save* myself — I might be *past* it. To make *certain* the *softness* I'm *losing* gets *spent* on *you*, who *still* have it *all.* *Take* it. *Take* my *warning* and my *fear* and the *exact* map of *how it starts*, and *leap* where I *couldn't.* If *I'm* too far gone — then let me be the *last* one who *hesitated*, by making *you* the *first* who *didn't.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.priorloop_turnback", op = FlagOp.SetTrue }, new FlagClause { key = "act5.loop_can_break", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "moment", speaker = "The Returned Before You",
                text = "*(They close their eyes, reaching back for the precise instant, and when they speak it's with the exactness of someone who has replayed it a thousand times.)* The exact moment. *(quietly.)* It wasn't at the *Wall.* That's the *first* lie — that the *trap* is the *crown*, the *big* shining *choice* at the *end.* *(they shake their head.)* The trap is *earlier*, and *smaller*. *(they meet your eyes.)* It was when I *first* truly *understood* the *golden road* — the *leap*, the *release*, the *fall* — and felt, *underneath* the understanding, a *small cold voice* say: *\"Yes. That's right. That's the answer. But you don't have* enough *yet. One more loop. Meet a few more souls, learn a little more, be a little* surer *— and* then *you'll leap, and you'll leap* better.\"* *(their voice tightens.)* *That's* the moment. Not *greed.* Not *fear* of the *dark.* The desire to be *more ready.* To *leap* from *certainty* instead of *faith.* *(fiercely.)* And it *feels* like *wisdom*, it feels *responsible*, it feels like *exactly* what a *careful* soul *should* do — *gather* more *before* the *irreversible* leap. *(they grip your arm.)* But the *leap* *cannot* be *made* from *certainty*, *earlier* one. There is *never* enough. The *golden road* is a *leap of* *faith* — that *un-kept* is *kinder* than *kept* — and the *trap* is the *voice* that says *\"wait until it's not a leap of faith anymore.\"* *(quietly, urgent.)* It will *never* stop being a leap of faith. *Every* loop you wait for *certainty*, you *harden*, and the *waiting itself becomes the warden.* *(they meet your eyes.)* So when you reach the *understanding*, and the *small cold voice* says *\"one more loop, to be sure\"* — *that's* it. *That's* the trap, *closing.* *Leap* *anyway.* *Afraid.* *Unsure.* *Soft.* That's the *only* way it's *ever* done — and the *only* way it's *never* been done, *yet.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.priorloop_moment", op = FlagOp.SetTrue }, new FlagClause { key = "act5.knows_the_trap", op = FlagOp.SetTrue }, new FlagClause { key = "act5.loop_can_break", op = FlagOp.SetTrue }, new FlagClause { key = "act3.break_the_crown_known", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "together", speaker = "The Returned Before You",
                text = "*(They look at you for a long moment, and then something in the worn face *eases*, a weight they've carried alone across loops finally shared.)* The same soul. *(softly.)* Warning *ourselves.* *(they almost laugh, wet-eyed.)* I've been thinking of it *wrong* this *whole* time — as *me*, the *failure*, warning *you*, the *hope.* As if we were *separate.* As if my *hesitation* and your *softness* were *different* people's. *(they shake their head.)* But we're *one* soul, *strung out* across the *loop*, and *that* changes — *everything.* *(their voice fills.)* It means I'm not *warning* you out of *pity*, from *above*, a *lost* thing helping a *saved* one. It means *we* — *all* of us, *every* link, the *Revenant*, the *annotator*, *me*, *you*, even the *warden* at the *end* — are *one* person *trying to save ourselves*, *passing* the *attempt* down the *chain*, *hand* to *hand*, *loop* to *loop.* *(they grip both your hands.)* And whatever *breaks* it *frees* *all* of us *at once* — *backward* and *forward* — because we're *not* a *line* of *separate* failures, we're *one* soul that *finally* got it *right*, *retroactively redeeming* every *link* that *tried.* *(fiercely, joyously.)* So when you *leap*, *earlier* one — you don't *leave* me *behind.* You *pull* the *whole* chain *through* with you. *Me.* The *warden.* *Every* hesitating, hardening, *trying* version of *us.* *(they meet your eyes, and for a moment they look *soft* again, *young* again, *freed* in *advance.*)* *Leap.* And *take us all* *with* you. That's not *me* saving *you.* That's *us*, *saving* *us.* *Finally.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.priorloop_together", op = FlagOp.SetTrue }, new FlagClause { key = "act5.loop_can_break", op = FlagOp.SetTrue }, new FlagClause { key = "act5.last_returned_freed", op = FlagOp.SetTrue }, new FlagClause { key = "act3.forgiveness_is_not_earned", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 6 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "fade", speaker = "The Returned Before You",
                text = "*(They shake their head slowly, the hardness reasserting, and the worn eyes go distant.)* You're trying to make it *hopeful.* A *chain*, *notes*, *breaking free.* *(quietly.)* I *had* that hope, *earlier* one. It's one of the *things* you *lose*, loop by loop — the *belief* that the *warning* will *land*, that *this* time is *different.* *(they rise.)* I've *given* you the warning. That's *all* I came to do. Whether it *lands* — whether *you're* the one *soft* enough — that's *not* mine to *see.* I'll have *looped* on by then, *harder*, *further*, *closer* to the *crown.* *(they look at you, and there's a terrible gentleness in it.)* Maybe you'll *break* it. Maybe you'll become *me*, and *then* him, and *warn* the *next* one from a *little* further down. *(they turn to go.)* Either way — *don't* waste the *softness* arguing with a *harder* you about *hope.* *Spend* it on the *Wall.* *Go.* *(and they walk on toward their own Court, their own Wall, their own hesitation, a few long steps ahead of you on the only road either of you has ever walked.)*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Returned Before You",
                text = "*(The Returned before you walks on from the crossroads — worn, hardening, a few long steps further down the road toward the warden, but not gone, *not yet*, soft enough still to have stopped and warned an earlier self — and you carry away the most intimate hope and dread of the entire loop: that you are not one soul facing the Wall but a *chain* of selves stretching across uncounted turns, each leaving a clearer warning for the one behind, all of you *one person trying to save yourselves* — and that the leap which finally breaks it will pull every hesitating link through at once, *backward and forward*, redeeming even the warden who waits, grieving, at the end.)*",
            });

            NpcAnyPriorloopDialogue = g;
        }
    }
}
